class Ui_video_change(QtWidgets.QWidget):
    def __init__(self, video_cap_list, mainwindow, sql_class):
        super().__init__()
        self.sql_class = sql_class
        self.mainwindow = mainwindow
        self.video_cap_list = video_cap_list  # 摄像头字典对象 存放key=名称 value=[ip,账号,密码]
