        self.name_edit = QtWidgets.QLineEdit(self)
        self.IP_edit = QtWidgets.QLineEdit(self)
        self.zhanghao_edit = QtWidgets.QLineEdit(self)
        self.mima_edit = QtWidgets.QLineEdit(self)

        # 设置控件属性
        self.name_edit.setPlaceholderText("请输入摄像头名称")
        self.IP_edit.setPlaceholderText("请输入摄像头IP")
        self.zhanghao_edit.setPlaceholderText("请输入摄像头账号")
