        self.form_layout.addRow("密码:", self.mima_edit)

        # 创建按钮布局
        self.button_layout = QtWidgets.QHBoxLayout()
        self.main_layout.addLayout(self.button_layout)

        self.btn_video_add = QtWidgets.QPushButton("添加视频", self)
        self.btn_delete_video = QtWidgets.QPushButton("删除视频", self)
        self.btn_back = QtWidgets.QPushButton("关闭", self)

        # 将按钮添加到布局
        self.button_layout.addWidget(self.btn_video_add)
        self.button_layout.addWidget(self.btn_delete_video)
        self.button_layout.addWidget(self.btn_back)

        # 连接信号与槽
        self.btn_video_add.clicked.connect(self.video_add_cap)
        self.btn_delete_video.clicked.connect(self.video_del_cap)
        self.btn_back.clicked.connect(lambda: self.change_video_show(self.mainwindow, self))

